#!/usr/bin/env python
"""
Simple test script to verify widget attribute escaping.
This script tests the escaping logic without importing Django.
"""

import html
from typing import Any, Dict

# Minimal SafeString mock
class SafeString(str):
    def __html__(self):
        return str(self)

def mark_safe(s):
    return SafeString(s)

def escape(text):
    """Return the given text with ampersands, quotes and angle brackets encoded."""
    return SafeString(html.escape(str(text)))

def conditional_escape(text):
    """
    Similar to escape(), except that it doesn't operate on pre-escaped strings.
    This function relies on the __html__ convention.
    """
    if hasattr(text, "__html__"):
        return text.__html__()
    else:
        return escape(text)

# Test implementations
def build_attrs_original(base_attrs: Dict[str, Any], extra_attrs=None) -> Dict[str, Any]:
    """Original implementation without escaping."""
    return {**base_attrs, **(extra_attrs or {})}

def build_attrs_fixed(base_attrs: Dict[str, Any], extra_attrs=None) -> Dict[str, Any]:
    """Fixed implementation with escaping."""
    attrs = {**base_attrs, **(extra_attrs or {})}
    # Escape attribute values to prevent XSS vulnerabilities.
    # Use conditional_escape to respect mark_safe'd values.
    return {
        key: conditional_escape(value) if value not in (True, False, None) else value
        for key, value in attrs.items()
    }

# Test cases
test_cases = [
    ('Value with "quotes"', 'Should escape double quotes'),
    ('Value with <brackets>', 'Should escape angle brackets'),
    ('A & B', 'Should escape ampersands'),
    ("Single 'quotes'", 'Should escape single quotes'),
    (mark_safe('<b>bold</b>'), 'Should preserve mark_safe values'),
    (None, 'Should handle None values'),
    (True, 'Should handle True values'),
    (False, 'Should handle False values'),
]

print("Testing widget attribute escaping fix...")
print("=" * 70)

test_passed = 0
test_failed = 0

for input_value, description in test_cases:
    print(f"\nTest: {description}")
    print(f"Input value: {repr(input_value)}")

    original_result = build_attrs_original({}, {'test-attr': input_value})
    fixed_result = build_attrs_fixed({}, {'test-attr': input_value})

    original_value = original_result.get('test-attr')
    fixed_value = fixed_result.get('test-attr')

    print(f"Original result: {repr(original_value)}")
    print(f"Fixed result:    {repr(fixed_value)}")

    if input_value in (True, False, None):
        # For special values, results should be the same
        if original_value == fixed_value:
            print("✓ PASS: Special values handled correctly")
            test_passed += 1
        else:
            print("✗ FAIL: Special values not handled correctly")
            test_failed += 1
    elif isinstance(input_value, SafeString) or hasattr(input_value, '__html__'):
        # For mark_safe'd values, results should be the same (but might be different object type)
        if str(original_value) == str(fixed_value):
            print("✓ PASS: mark_safe values preserved")
            test_passed += 1
        else:
            print("✗ FAIL: mark_safe values not preserved")
            test_failed += 1
    else:
        # For regular strings, fixed version should escape
        if isinstance(fixed_value, SafeString):
            print("✓ PASS: Value is escaped and marked safe")
            test_passed += 1
            # Check that escaping happened
            if '&quot;' in str(fixed_value) and '"' in str(input_value):
                print("  ✓ Double quotes escaped correctly")
            elif '&lt;' in str(fixed_value) and '<' in str(input_value):
                print("  ✓ Angle brackets escaped correctly")
            elif '&amp;' in str(fixed_value) and '&' in str(input_value):
                print("  ✓ Ampersands escaped correctly")
            elif '&#x27;' in str(fixed_value) and "'" in str(input_value):
                print("  ✓ Single quotes escaped correctly")
        else:
            print("✗ FAIL: Value is not marked safe")
            test_failed += 1

print("\n" + "=" * 70)
print(f"Test Results: {test_passed} passed, {test_failed} failed")
print("\nSummary:")
print("- Original build_attrs returns raw values")
print("- Fixed build_attrs escapes values and marks them safe")
print("- mark_safe'd values are preserved without double-escaping")
print("- Special values (True, False, None) are not escaped")

if test_failed == 0:
    print("\n✓ All tests passed!")
    exit(0)
else:
    print(f"\n✗ {test_failed} test(s) failed!")
    exit(1)

